<template>
    <div>
          <loader :isVisible="isLoading"></loader>
          <dynamic-form lang="en" ref="BarcodeReport" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
      
          <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer  v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
      </div>
    </template>
    <script>
    import DataService from '../../services/DataService';
    import ReportViewer from '../HrReport/ReportViewer.vue';
    
    
    export default {
  
        components: { ReportViewer },  
         data() {
             return {
                CompanyReportDDLTypes: [],
                dtFrom: null,
                dtTO: null,
                reportPath: null,
                parameter: [],
                QRStatusId:null,
                mindate:null,
                popover:null,
                FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                    {
                        astype: "MultiSelectField",
                        label: "Project",
                        name: "Project",
                        value: "",
                        placeholder: "Select",
                        mode: "tag",
                        config:{
                          options: [],
                          onChange: this.onChangeDropdown
                        },
                        validationRules: {"required": false},
                    },
                    {
                      astype: "MultiSelectField",
                      label: "Category",
                      name: "Category",
                      value: [],
                      placeholder: "Select",
                      mode: "tag",
                      config:{
                        options: []
                      },
                      validationRules: {"required": false},
                    },
                    {
                      astype: "MultiSelectField",
                      label: "Trip",
                      name: "Trip",
                      value: [],
                      placeholder: "Select",
                      mode: "tag",
                      config:{
                        options: []
                      },
                      validationRules: {"required": false},
                    },
                    {
                      astype: "MultiSelectField",
                      label: "User",
                      name: "User",
                      value: [],
                      placeholder: "Select",
                      mode: "tag",
                      config:{
                        options: []
                      },
                      validationRules: {"required": false},
                    },
                    {
                      astype: "MultiSelectField",
                      label: "Approver",
                      name: "Approver",
                      value: [],
                      placeholder: "Select",
                      mode: "tag",
                      config:{
                        options: []
                      },
                      validationRules: {"required": false},
                    },
                    {
                      astype: "SelectField",
                      label: "Status",
                      name: "Status",
                      value: [],
                      placeholder: "Select",
                      config:{
                        options: []
                      },
                      validationRules: {"required": false},
                    },
                    {
                        astype: "TextField",
                        label: this.$t('ExpenseTitletext'),
                        name: "ExpenseTitle",
                        value: "",
                        placeholder: "",
                        validationRules: { "required": false, max: 250 },
                    },
                    {
                         astype: "DateField",
                         label: 'Date From (M/D/YYYY)',
                         name: "ExpenseDateFrom",
                         value: '',
                         placeholder: "M/D/YYYY",
                         validationRules: {"required": false},
                         config: {
                             format: "MM/DD/YYYY"
                         }
                     },
                     {
                         astype: "DateField",
                         label: 'Date To (M/D/YYYY)',
                         name: "ExpenseDateTo",
                         value: '',
                         placeholder: "M/D/YYYY",
                         validationRules: {"required": false},
                         config: {
                             format: "MM/DD/YYYY"
                         }
                     },
                     {
                      astype: "RadioField",
                      label: "Group By",
                      name: "GroupBy",
                      value: 1,
                      config:{
                        options: [{value: "1", name: "Project"},{value: "2", name: "Category"},{value: "3", name: "Trip"}]
                      },
                      validationRules: {"required": false}
                    }
                    ],
                  }
                ],
                  buttons: [
                      {
                          type: "submit",
                          class: "btn btn-success",
                          text: "<i class='fa fa-search pr-2'></i>Search",
                      },
                      { 
                          type: "button",
                          class: "btn btn-danger",
                          text: "<i class='fa fa-close pr-2'></i>Clear all",
                          onClick: this.ClearAll
                      },
                  ],
             }
         },
         created: function () {
            debugger;
            var vm = this;
            vm.GetProjectByCompanyIdAndUserId();
            vm.GetAllCategoriesByCompanyId();
            vm.GetTripNameDDL();
            vm.GetUsersByProjectIds();
            vm.GetStatusList();
            vm.ExpenseGetApproverListing();
         },
         methods: {
            ClearAll: function () {
                var vm = this;
                (vm.FormSchema)[0].Data[0].value = '';
                (vm.FormSchema)[0].Data[1].value = '';
                (vm.FormSchema)[0].Data[2].value = '';
                (vm.FormSchema)[0].Data[3].value = '';
                (vm.FormSchema)[0].Data[4].value = '';
                (vm.FormSchema)[0].Data[5].value = '';
                (vm.FormSchema)[0].Data[6].value = '';
                (vm.FormSchema)[0].Data[7].value = '';
                (vm.FormSchema)[0].Data[8].value = '';
                (vm.FormSchema)[0].Data[9].value = 1;
                // vm.parameter = [];
            },

            GetUsersByProjectIds:function(){    
            var vm = this;    
            var params=`projectIds=&moduleName=Project`
            DataService.GetUsersByProjectIds(params).then(function (response) {      
                response.data.forEach((item)=>{
                (vm.FormSchema)[0].Data[3].config.options.push({
                        value: `${item.USER_ID}`,
                        name: item.USER_NAME
                    });
                })
            });
            } ,
            GetTripNameDDL: function () {
            var vm = this;
            DataService.GettTripListingddl().then(function (response) {
                  response.data.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[2].config.options.push({
                            value: item.TRIP_ID,
                            name: item.TRIP_NAME
                        });
                    });
                });
            },
            GetStatusList: function () {
            var vm = this;
            var url = "langCode=" + 'lang' + "&statusType=" + 'StatusType' + "&hasglobal=true";
            DataService.GetStatusList(url).then(function (response) {
                response.data.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[5].config.options.push({
                            value: item.STATUS_ID,
                            name: item.STATUS
                        });
                    });
            });
        },

      ExpenseGetApproverListing  :function(){
            let params = {};
            var vm=this;
            params["IsEncrptedId"] = '';
            params["moduleName"] = 'Expenses';
            DataService.ExpenseGetUserListing(params).then(function (response) {
                response.data.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[4].config.options.push({
                            value: item.value,
                            name: item.name
                        });
                    });
            });
        },
      GetProjectByCompanyIdAndUserId: async function () {
                var vm = this;
                await DataService.GetProjectByCompanyIdAndUserId().then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var Data = response.data;
                        Data.forEach(element => {
                            var Obj = {
                                name: element.projectName,
                                value: element.projectId
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
        },

            GetAllCategoriesByCompanyId: async function () {
                var vm = this;
                await DataService.GetAllCategoriesByCompanyId().then((response) => {
                    debugger;
                    if (response.data.length > 0) {
                        var Data = response.data;
                        Data.forEach(element => {
                            var Obj = {
                                name: element.categorY_NAME,
                                value: element.expensE_CATEGORY_ID
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
            onSubmit:function(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
            var vm=this;
            vm.isLoading=true;
            vm.reportPath = '';      
            vm.parameter=[];
            var reportModel={
            reportName:'expensereport',
            moduleName:'Expense',
            projectIds:e.Project.length == undefined ? '' : e.Project.length ==0 ?'': e.Project.length > 0 ? e.Project.map(item => item.value).join(",") : '',
            categoryIds:e.Category.length == undefined ? '' : e.Category.length ==0 ?'': e.Category.length > 0 ? e.Category.map(item => item.value).join(",") : '',
            dateFrom:e.ExpenseDateFrom,
            dateTo:e.ExpenseDateTo,
            approverIds:e.Approver.length == undefined ? '' :  e.Approver.length ==0 ?'': e.Approver.length > 0 ? e.Approver.map(item => item.value).join(",") : '', 
            tripIds:e.Trip.length == undefined ? '' :  e.Trip.length ==0 ?'': e.Trip.length > 0 ? e.Trip.map(item => item.value).join(",") : '',
            userIds:e.User.length == undefined ? '' :  e.User.length ==0 ?'': e.User.length > 0 ? e.User.map(item => item.value).join(",") : '',
            StatusIds:e.Status.length == undefined ? '' : e.Status.length ==0 ?'': e.Status.length > 0 ? e.Status.map(item => item.value).join(",") : '',  
            expTitle:e.ExpenseTitle,
            groupByVal:e.GroupBy.toString()            
        }  
        var objectPostString = JSON.stringify(reportModel);     
        DataService.ReportMain(objectPostString).then(response => {  
                debugger;                                    
                 vm.reportPath=response.data.ReportPath;
                 vm.parameter=response.data.parameters;
            });
            vm.isLoading = false;
        }, 
 
        }
     }
     
    </script>